{
  "executive_summary": "Payment processing service with customer-managed encryption, sub-50ms P99 latency, full audit logging, offline resilience, and zero-downtime key rotation. The core architectural tension is between strong encryption with external CMK and the 50ms P99 + offline requirements — resolved via a local key cache with envelope encryption pattern. Field-level audit logging at 50ms P99 requires careful design to avoid the audit path becoming the bottleneck.",

  "architecture": {
    "components": [
      {
        "name": "Payment Gateway",
        "responsibility": "Accepts payment requests, validates input, orchestrates the payment pipeline. Stateless request handler.",
        "boundaries": "Owns request validation and routing only. Does NOT touch raw payment data — delegates to Crypto Engine."
      },
      {
        "name": "Crypto Engine",
        "responsibility": "Encrypts/decrypts payment fields using cached Data Encryption Keys (DEKs). Implements envelope encryption: DEKs encrypted by CMKs. All crypto operations are in-process to meet latency targets.",
        "boundaries": "Owns all cryptographic operations. Never exposes plaintext DEKs outside its memory space. Holds the local key cache."
      },
      {
        "name": "Local Key Cache",
        "responsibility": "In-memory cache of decrypted DEKs with TTL. Pre-fetches and warms keys on startup and rotation events. Enables offline operation by caching active DEKs with configurable TTL (default: 24h).",
        "boundaries": "Sits inside the Crypto Engine process. Cache entries are encrypted DEK bundles that are decrypted on load. Memory is pinned (mlock) to prevent swapping to disk."
      },
      {
        "name": "Key Management Proxy",
        "responsibility": "Mediates between Crypto Engine and external KMS (AWS KMS, GCP KMS, Azure Key Vault, or HSM). Handles DEK generation, CMK-based DEK wrapping/unwrapping, and key rotation orchestration.",
        "boundaries": "Only component that communicates with external KMS. Circuit breaker pattern isolates KMS failures from payment processing."
      },
      {
        "name": "Payment Processor",
        "responsibility": "Executes the actual payment logic — authorization, capture, settlement. Operates on encrypted data where possible, decrypts only the fields needed for each operation.",
        "boundaries": "Receives already-decrypted fields from Crypto Engine. Never stores plaintext. Business logic only."
      },
      {
        "name": "Audit Logger",
        "responsibility": "Captures every field-level access (read, write, decrypt) as structured audit events. Writes to an append-only log asynchronously via a bounded in-memory ring buffer.",
        "boundaries": "Fire-and-forget from the hot path (async). Guarantees at-least-once delivery to durable storage. Does NOT block payment processing."
      },
      {
        "name": "Key Rotation Orchestrator",
        "responsibility": "Manages the 30-day key rotation lifecycle: generates new DEK, re-encrypts active data under new DEK, retires old DEK after grace period. Runs as a background process with distributed locking.",
        "boundaries": "Never touches the payment hot path. Operates on stored (encrypted) data. Uses dual-write period to avoid maintenance windows."
      }
    ],
    "interfaces": [
      {
        "from": "Payment Gateway",
        "to": "Crypto Engine",
        "contract": "encrypt(fields: Map<FieldName, PlaintextValue>, keyId: KeyRef) -> Map<FieldName, CiphertextEnvelope>; decrypt(fields: Map<FieldName, CiphertextEnvelope>) -> Map<FieldName, PlaintextValue>",
        "coupling_type": "tight — in-process call for latency"
      },
      {
        "from": "Crypto Engine",
        "to": "Local Key Cache",
        "contract": "getKey(keyId: KeyRef) -> DecryptedDEK | CacheMiss; warmKeys(keyIds: KeyRef[]) -> void",
        "coupling_type": "tight — in-memory, same process"
      },
      {
        "from": "Local Key Cache",
        "to": "Key Management Proxy",
        "contract": "unwrapDEK(wrappedDEK: bytes, cmkId: string) -> DecryptedDEK; generateDEK(cmkId: string) -> WrappedDEK + DecryptedDEK",
        "coupling_type": "loose — async pre-fetch, circuit breaker on failure"
      },
      {
        "from": "Key Management Proxy",
        "to": "External KMS",
        "contract": "Standard KMS API (e.g., AWS KMS Decrypt/GenerateDataKey). Circuit breaker with 5s timeout, 3 retries.",
        "coupling_type": "loose — external dependency, failure-tolerant"
      },
      {
        "from": "Payment Gateway",
        "to": "Audit Logger",
        "contract": "logAccess(event: AuditEvent) -> void (fire-and-forget). AuditEvent = {timestamp, requestId, userId, fieldName, accessType, keyVersion, sourceIP}",
        "coupling_type": "loose — async, non-blocking ring buffer"
      },
      {
        "from": "Key Rotation Orchestrator",
        "to": "Crypto Engine",
        "contract": "rotateKey(oldKeyId: KeyRef, newKeyId: KeyRef) -> RotationResult. Re-encrypts in batches, supports rollback.",
        "coupling_type": "loose — background process, distributed lock"
      }
    ],
    "data_flow": "1) Request arrives at Payment Gateway → 2) Gateway asks Crypto Engine to decrypt needed fields → 3) Crypto Engine checks Local Key Cache for DEK (cache hit: ~0.1ms; cache miss: unwrap via KMS Proxy ~5-15ms) → 4) Fields decrypted in-process using AES-256-GCM → 5) Audit Logger captures field access event asynchronously → 6) Payment Processor executes business logic → 7) Result fields re-encrypted → 8) Encrypted response stored/returned. Key rotation happens offline: Orchestrator generates new DEK, re-encrypts stored data in batches, dual-key read period allows zero-downtime cutover.",
    "patterns_used": [
      {
        "pattern": "Envelope Encryption",
        "rationale": "DEKs encrypt data locally (fast, offline-capable). CMKs encrypt DEKs (secure, customer-managed). Decouples data encryption speed from KMS latency. This is the ONLY pattern that satisfies both the 50ms P99 and the CMK requirement simultaneously."
      },
      {
        "pattern": "Circuit Breaker (on KMS Proxy)",
        "rationale": "External KMS unavailability must not cascade into payment failures. Circuit breaker trips after N failures, falls back to cached DEKs. Directly addresses requirement #4 (offline operation)."
      },
      {
        "pattern": "Async Append-Only Audit Log",
        "rationale": "Synchronous audit logging would add 2-10ms per field access, blowing the 50ms budget on multi-field payments. Async fire-and-forget with bounded ring buffer keeps audit off the hot path while guaranteeing at-least-once delivery."
      },
      {
        "pattern": "Dual-Write Key Rotation",
        "rationale": "During rotation, both old and new DEKs are active readers. New writes use the new DEK. Background process re-encrypts old data. No maintenance window needed because reads always check the key version header on each ciphertext envelope."
      },
      {
        "pattern": "Pinned Memory for Key Material",
        "rationale": "DEKs in the Local Key Cache must never be swapped to disk. Using mlock/VirtualLock prevents the OS from paging sensitive key material to swap space."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Payment Processing",
        "classification": "core",
        "aggregates": ["Payment (root: PaymentId — holds encrypted fields, status, audit trail reference)", "PaymentMethod (value object — tokenized card/account data)"]
