      },
      {
        "upstream": "Payment Processing",
        "downstream": "Audit",
        "relationship": "Published Language — Payment context emits structured AuditEvents that Audit context consumes. Decoupled via async event bus."
      },
      {
        "upstream": "Cryptographic Operations",
        "downstream": "Payment Processing",
        "relationship": "Open Host Service — Crypto Engine exposes a clean encrypt/decrypt API. Payment Processing is a consumer."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Async audit logging (fire-and-forget with ring buffer) instead of synchronous write-ahead audit",
      "gains": "Keeps audit off the hot path. Saves 2-10ms per payment. Essential for 50ms P99.",
      "sacrifices": "Tiny window where an audit event could be lost if the process crashes between ring buffer write and durable flush. NOT zero-loss — it's at-least-once with a small window of potential loss.",
      "alternatives_considered": ["Synchronous audit write (rejected: adds 5-15ms, blows P99 budget)", "Write-ahead log before payment (rejected: doubles latency)", "Sidecar audit agent (viable but adds deployment complexity)"]
    },
    {
      "decision": "In-memory DEK cache with 24h TTL for offline resilience",
      "gains": "Payments continue processing when KMS is unavailable. Cache hits are sub-millisecond. Directly satisfies requirements #2 and #4.",
      "sacrifices": "Cached DEKs in memory are a high-value target. If process memory is compromised, DEKs are exposed. 24h TTL means a revoked key could still be used for up to 24h.",
      "alternatives_considered": ["No cache, always call KMS (rejected: 15-50ms per call, no offline)", "Hardware Security Module locally (ideal but expensive and complex)", "Shorter TTL of 1h (trade-off: reduces offline window, increases KMS dependency)"]
    },
    {
      "decision": "Envelope encryption with AES-256-GCM for field-level encryption",
      "gains": "Field-level granularity means we decrypt only what's needed per operation. GCM provides authentication + encryption in one pass (~0.1ms per field). Envelope pattern decouples speed from KMS.",
      "sacrifices": "More complex than full-record encryption. Each field carries overhead (IV + auth tag + key version = ~60 bytes per field). Storage cost increases ~10-15%.",
      "alternatives_considered": ["Full-record encryption (simpler but decrypts everything even when only one field is needed — wasteful and harder to audit per-field)", "Format-preserving encryption (preserves field format but weaker security properties and slower)"]
    },
    {
      "decision": "Dual-write key rotation instead of big-bang re-encryption",
      "gains": "Zero downtime. No maintenance window. Gradual migration. Rollback-safe.",
      "sacrifices": "Complexity: readers must handle multiple key versions. Brief period of increased storage (two encrypted copies during migration). Rotation takes hours/days for large datasets instead of minutes.",
      "alternatives_considered": ["Big-bang re-encryption during maintenance window (rejected: violates requirement #5)", "Lazy re-encryption on read (rejected: old data never accessed is never re-encrypted, compliance risk)"]
    }
  ],

  "flexibility_points": [
    {
      "area": "KMS Provider",
      "evolution_path": "Anti-Corruption Layer (KMS Proxy) means swapping from AWS KMS to GCP KMS or on-prem HSM requires changing only the proxy adapter. Zero impact on payment logic or crypto engine."
    },
    {
      "area": "Encryption Algorithm",
      "evolution_path": "CiphertextEnvelope includes algorithm identifier. New algorithms can be introduced per-key-version. Old data remains readable. Enables post-quantum migration path."
    },
    {
      "area": "Audit Storage Backend",
      "evolution_path": "Audit Logger writes to an abstract sink. Can swap from local append-only log to Kafka, S3, or a SIEM without touching payment code."
    },
    {
      "area": "Key Rotation Policy",
      "evolution_path": "RotationPolicy is a value object. Changing from 30-day to 7-day rotation is a configuration change, not a code change."
    }
  ],

  "rigidity_points": [
    {
      "area": "Envelope Encryption Pattern",
      "reason": "This is load-bearing. The entire latency model, offline capability, and key rotation strategy depend on the DEK/CMK separation. Changing this would require a full redesign."
    },
    {
      "area": "Field-Level Encryption Granularity",
      "reason": "Audit requirement (#3) demands per-field access logging. This commits us to field-level encryption. Moving to record-level later would break audit compliance."
    },
    {
      "area": "Async Audit on Hot Path",
      "reason": "The 50ms P99 budget leaves no room for synchronous audit. If compliance requirements change to demand synchronous audit-before-process, the latency target becomes infeasible without hardware changes."
    }
  ],

  "risks": [
    {
      "risk": "Async audit log gap: process crash between ring buffer write and durable flush loses audit events. Compliance auditors may reject this.",
      "severity": "critical",
      "mitigation": "1) Size the ring buffer to flush every 10ms (small window). 2) Use a memory-mapped file as the ring buffer so OS crash recovery can reclaim events. 3) Get explicit compliance sign-off on the at-least-once guarantee with measured loss window. 4) If rejected, fall back to synchronous audit and renegotiate the 50ms P99 target."
    },
    {
      "risk": "24h DEK cache TTL means a compromised or revoked key remains usable for up to 24 hours in offline mode.",
      "severity": "high",
      "mitigation": "1) Implement push-based cache invalidation (KMS sends revocation event). 2) Reduce TTL when online (e.g., 1h online, 24h offline). 3) Monitor for anomalous decryption patterns. 4) Accept the risk for offline scenario — document in threat model."
    },
    {
      "risk": "The 50ms P99 budget is extremely tight. Field-level encrypt + decrypt + audit + business logic + network overhead must all fit. Any degradation in one component cascades.",
      "severity": "high",
      "mitigation": "1) Budget allocation: crypto 5ms, audit 0.5ms (async), business logic 10ms, serialization 5ms, network 20ms, headroom 9.5ms. 2) Pre-warm key cache on startup. 3) Use hardware AES-NI instructions. 4) Load test at 2x expected throughput to validate."
    },
    {
      "risk": "Key rotation for large datasets (millions of records) could take days with dual-write approach. During this window, reads must check multiple key versions, adding latency.",
      "severity": "medium",
      "mitigation": "1) Batch re-encryption with configurable parallelism. 2) Key version lookup is O(1) via version header on each ciphertext envelope — not a scan. 3) Set SLA for rotation completion (e.g., 72h max). 4) Monitor rotation progress with alerting."
